import React, { useState } from 'react';

const App = () => {
  const [inputValue, setInputValue] = useState('');
  const [messages, setMessages] = useState([]);

  const handleInputChange = (e) => {
    setInputValue(e.target.value);
  };

  const handleSendMessage = () => {
    setMessages([...messages, inputValue]);
    setInputValue('');
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#B7D7CD] p-4 rounded-lg">
        <input
          type="text"
          className="bg-transparent border-none outline-none p-2 w-full"
          value={inputValue}
          onChange={handleInputChange}
          placeholder="Type a message..."
        />
        <button
className="bg-[#C06C88] hover:bg-[#C06C88] hover:text-white text-white px-4 py-2 rounded-lg" onClick={handleSendMessage}>Send</button>
      </div>
      <div className="bg-[#B7D7CD] p-4 rounded-lg mt-4" id="messages">
        <ul>
          {messages.map((message, index) => (
            <li key={index}>{message}</li>
          ))}
        </ul>
      </div>
    </div>
  );
};

export default App;
